  1→//! Coverage-based test impact analysis.
  2→//!
  3→//! Maintains a coverage map recording which tests touch which source files,
  4→//! then uses that map to select the minimal test set for a given set of changes.
  5→//! The forward map (test → files) is the source of truth; the reverse map
  6→//! (file → tests) is derived at load time and never persisted.
  7→
  8→use std::collections::{BTreeMap, HashMap, HashSet};
  9→use std::path::{Path, PathBuf};
 10→
 11→use serde::{Deserialize, Serialize};
 12→
 13→use crate::file_lock::FileLock;
 14→use crate::scm;
 15→
 16→// ---------------------------------------------------------------------------
 17→// Constants
 18→// ---------------------------------------------------------------------------
 19→
 20→/// Relative path (within `.shatter/`) for the coverage map file.
 21→pub const COVERAGE_MAP_REL_PATH: &str = "test-markers/coverage-map.yaml";
 22→
 23→/// Relative path (within `.shatter/`) for tier marker directory.
 24→pub const TIER_MARKER_DIR: &str = "test-markers/tiers";
 25→
 26→/// Current schema version for the coverage map.
 27→pub const COVERAGE_MAP_VERSION: u32 = 1;
 28→
 29→// ---------------------------------------------------------------------------
 30→// Errors
 31→// ---------------------------------------------------------------------------
 32→
 33→/// Errors from test-impact-analysis operations.
 34→#[derive(Debug, thiserror::Error)]
 35→pub enum TiaError {
 36→    #[error("I/O error: {0}")]
 37→    Io(#[from] std::io::Error),
 38→
 39→    #[error("YAML parse error: {0}")]
 40→    Yaml(#[from] serde_yaml::Error),
 41→
 42→    #[error("SCM error: {0}")]
 43→    Scm(#[from] scm::ScmError),
 44→
 45→    #[error("runner error: {message}")]
 46→    Runner { message: String },
 47→
 48→    #[error("no coverage map found at {path}")]
 49→    NoCoverageMap { path: PathBuf },
 50→}
 51→
 52→// ---------------------------------------------------------------------------
 53→// Coverage map data model
 54→// ---------------------------------------------------------------------------
 55→
 56→/// Serialized coverage map (forward direction only).
 57→/// The reverse index is derived at load time.
 58→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
 59→pub struct CoverageMapData {
 60→    pub version: u32,
 61→    pub recorded_at: String,
 62→    /// Forward map: test identifier → files it touches.
 63→    pub entries: BTreeMap<String, TestEntry>,
 64→}
 65→
 66→/// Files touched by a single test, with content-addressable blob hashes.
 67→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
 68→pub struct TestEntry {
 69→    /// Relative path → git blob hash at recording time.
 70→    pub files: BTreeMap<String, String>,
 71→}
 72→
 73→/// In-memory coverage map with derived reverse index.
 74→#[derive(Debug)]
 75→pub struct CoverageMap {
 76→    pub data: CoverageMapData,
 77→    /// Derived: file path → test identifiers that touch it.
 78→    reverse: HashMap<String, Vec<String>>,
 79→}
 80→
 81→/// Result of querying the coverage map for affected tests.
 82→#[derive(Debug)]
 83→pub struct ImpactQuery {
 84→    /// Files that changed (relative paths).
 85→    pub changed_files: Vec<String>,
 86→    /// Tests affected by the changed files (deduplicated).
 87→    pub affected_tests: Vec<String>,
 88→    /// Tests whose recorded blob hashes no longer match current files.
 89→    pub stale_entries: Vec<String>,
 90→    /// Changed files not present in the coverage map.
 91→    pub unmapped_files: Vec<String>,
 92→}
 93→
 94→// ---------------------------------------------------------------------------
 95→// Tier markers
 96→// ---------------------------------------------------------------------------
 97→
 98→/// Marker written after a test tier passes successfully.
 99→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
100→pub struct TierMarker {
101→    pub tier: String,
102→    pub passed_at: String,
103→    pub git_commit: String,
104→}
105→
106→// ---------------------------------------------------------------------------
107→// CoverageMap implementation
108→// ---------------------------------------------------------------------------
109→
110→impl CoverageMap {
111→    /// Load the coverage map from `.shatter/<COVERAGE_MAP_REL_PATH>`.
112→    pub fn load(shatter_dir: &Path) -> Result<Self, TiaError> {
113→        let path = shatter_dir.join(COVERAGE_MAP_REL_PATH);
114→        if !path.exists() {
115→            return Err(TiaError::NoCoverageMap { path });
116→        }
117→        let contents = std::fs::read_to_string(&path)?;
118→        let data: CoverageMapData = serde_yaml::from_str(&contents)?;
119→        let reverse = build_reverse_index(&data.entries);
120→        Ok(Self { data, reverse })
121→    }
122→
123→    /// Create an empty coverage map.
124→    pub fn empty() -> Self {
125→        let data = CoverageMapData {
126→            version: COVERAGE_MAP_VERSION,
127→            recorded_at: String::new(),
128→            entries: BTreeMap::new(),
129→        };
130→        Self {
131→            reverse: HashMap::new(),
132→            data,
133→        }
134→    }
135→
136→    /// Save the coverage map atomically (tempfile + rename) under a file lock.
137→    pub fn save(&self, shatter_dir: &Path) -> Result<(), TiaError> {
138→        let path = shatter_dir.join(COVERAGE_MAP_REL_PATH);
139→        if let Some(parent) = path.parent() {
140→            std::fs::create_dir_all(parent)?;
141→        }
142→
143→        let _lock = FileLock::acquire(&path)?;
144→
145→        let yaml = serde_yaml::to_string(&self.data)?;
146→        let tmp_path = path.with_extension("yaml.tmp");
147→        std::fs::write(&tmp_path, yaml)?;
148→        std::fs::rename(&tmp_path, &path)?;
149→        Ok(())
150→    }
151→
152→    /// Update the forward map from coverage output, recompute blob hashes, rebuild reverse.
153→    pub fn update_from_coverage(
154→        &mut self,
155→        test_file_map: &BTreeMap<String, Vec<String>>,
156→        project_root: &Path,
157→    ) -> Result<(), TiaError> {
158→        for (test_id, files) in test_file_map {
159→            let mut file_hashes = BTreeMap::new();
160→            for file in files {
161→                let abs_path = project_root.join(file);
162→                if abs_path.exists() {
163→                    match scm::blob_hash(project_root, Path::new(file)) {
164→                        Ok(hash) => {
165→                            file_hashes.insert(file.clone(), hash);
166→                        }
167→                        Err(_) => {
168→                            // Skip files that can't be hashed (e.g. binary, missing)
169→                            continue;
170→                        }
171→                    }
172→                }
173→            }
174→            self.data
175→                .entries
176→                .insert(test_id.clone(), TestEntry { files: file_hashes });
177→        }
178→
179→        self.data.recorded_at = now_iso8601();
180→        self.reverse = build_reverse_index(&self.data.entries);
181→        Ok(())
182→    }
183→
184→    /// Query: given changed files (relative paths), return affected tests.
185→    pub fn query_affected(&self, changed_files: &[String]) -> ImpactQuery {
186→        let mut affected_set = HashSet::new();
187→        let mut unmapped = Vec::new();
188→
189→        for file in changed_files {
190→            if let Some(tests) = self.reverse.get(file) {
191→                for t in tests {
192→                    affected_set.insert(t.clone());
193→                }
194→            } else {
195→                unmapped.push(file.clone());
196→            }
197→        }
198→
199→        let mut affected_tests: Vec<String> = affected_set.into_iter().collect();
200→        affected_tests.sort();
201→
202→        ImpactQuery {
203→            changed_files: changed_files.to_vec(),
204→            affected_tests,
205→            stale_entries: Vec::new(),
206→            unmapped_files: unmapped,
207→        }
208→    }
209→
210→    /// Find tests whose recorded blob hashes no longer match current file content.
211→    pub fn find_stale_entries(&self, project_root: &Path) -> Vec<String> {
212→        let mut stale = Vec::new();
213→        for (test_id, entry) in &self.data.entries {
214→            for (file, recorded_hash) in &entry.files {
215→                match scm::blob_hash(project_root, Path::new(file)) {
216→                    Ok(current_hash) => {
217→                        if &current_hash != recorded_hash {
218→                            stale.push(test_id.clone());
219→                            break;
220→                        }
221→                    }
222→                    Err(_) => {
223→                        // File missing or not hashable → stale
224→                        stale.push(test_id.clone());
225→                        break;
226→                    }
227→                }
228→            }
229→        }
230→        stale.sort();
231→        stale
232→    }
233→
234→    /// Access the reverse index.
235→    pub fn reverse_index(&self) -> &HashMap<String, Vec<String>> {
236→        &self.reverse
237→    }
238→}
239→
240→// ---------------------------------------------------------------------------
241→// Reverse index builder (pure function)
242→// ---------------------------------------------------------------------------
243→
244→/// Build the reverse index: file → [test_ids] from the forward map.
245→pub fn build_reverse_index(
246→    entries: &BTreeMap<String, TestEntry>,
247→) -> HashMap<String, Vec<String>> {
248→    let mut reverse: HashMap<String, Vec<String>> = HashMap::new();
249→    for (test_id, entry) in entries {
250→        for file in entry.files.keys() {
251→            reverse
252→                .entry(file.clone())
253→                .or_default()
254→                .push(test_id.clone());
255→        }
256→    }
257→    // Sort each list for deterministic output
258→    for tests in reverse.values_mut() {
259→        tests.sort();
260→        tests.dedup();
261→    }
262→    reverse
263→}
264→
265→// ---------------------------------------------------------------------------
266→// Tier marker operations
267→// ---------------------------------------------------------------------------
268→
269→/// Write a tier marker after successful test run.
270→pub fn write_tier_marker(
271→    shatter_dir: &Path,
272→    tier: &str,
273→    git_commit: &str,
274→) -> Result<(), TiaError> {
275→    let dir = shatter_dir.join(TIER_MARKER_DIR);
276→    std::fs::create_dir_all(&dir)?;
277→
278→    let marker = TierMarker {
279→        tier: tier.to_string(),
280→        passed_at: now_iso8601(),
281→        git_commit: git_commit.to_string(),
282→    };
283→
284→    let path = dir.join(format!("{tier}.yaml"));
285→    let yaml = serde_yaml::to_string(&marker)?;
286→    std::fs::write(&path, yaml)?;
287→    Ok(())
288→}
289→
290→/// Read a tier marker, returning None if it doesn't exist.
291→pub fn read_tier_marker(
292→    shatter_dir: &Path,
293→    tier: &str,
294→) -> Result<Option<TierMarker>, TiaError> {
295→    let path = shatter_dir.join(TIER_MARKER_DIR).join(format!("{tier}.yaml"));
296→    if !path.exists() {
297→        return Ok(None);
298→    }
299→    let contents = std::fs::read_to_string(&path)?;
300→    let marker: TierMarker = serde_yaml::from_str(&contents)?;
301→    Ok(Some(marker))
302→}
303→
304→/// Check whether a tier marker is fresh (matches the given commit).
305→pub fn is_tier_fresh(
306→    shatter_dir: &Path,
307→    tier: &str,
308→    current_commit: &str,
309→) -> Result<bool, TiaError> {
310→    match read_tier_marker(shatter_dir, tier)? {
311→        Some(marker) => Ok(marker.git_commit == current_commit),
312→        None => Ok(false),
313→    }
314→}
315→
316→// ---------------------------------------------------------------------------
317→// Helpers
318→// ---------------------------------------------------------------------------
319→
320→fn now_iso8601() -> String {
321→    // Use a simple approach without chrono dependency
322→    let output = std::process::Command::new("date")
323→        .args(["--iso-8601=seconds"])
324→        .output();
325→    match output {
326→        Ok(o) if o.status.success() => {
327→            String::from_utf8_lossy(&o.stdout).trim().to_string()
328→        }
329→        _ => "unknown".to_string(),
330→    }
331→}
