337→#[cfg(test)]
338→mod tests {
339→    use super::*;
340→
341→    #[test]
342→    fn build_reverse_index_basic() {
343→        let mut entries = BTreeMap::new();
344→        entries.insert(
345→            "test_a".to_string(),
346→            TestEntry {
347→                files: BTreeMap::from([
348→                    ("src/foo.rs".to_string(), "aaa".to_string()),
349→                    ("src/bar.rs".to_string(), "bbb".to_string()),
350→                ]),
351→            },
352→        );
353→        entries.insert(
354→            "test_b".to_string(),
355→            TestEntry {
356→                files: BTreeMap::from([("src/foo.rs".to_string(), "aaa".to_string())]),
357→            },
358→        );
359→
360→        let reverse = build_reverse_index(&entries);
361→        assert_eq!(reverse.get("src/foo.rs").map(|v| v.len()), Some(2));
362→        assert_eq!(reverse.get("src/bar.rs").map(|v| v.len()), Some(1));
363→        assert!(reverse.get("src/foo.rs").unwrap().contains(&"test_a".to_string()));
364→        assert!(reverse.get("src/foo.rs").unwrap().contains(&"test_b".to_string()));
365→    }
366→
367→    #[test]
368→    fn build_reverse_index_empty() {
369→        let entries = BTreeMap::new();
370→        let reverse = build_reverse_index(&entries);
371→        assert!(reverse.is_empty());
372→    }
373→
374→    #[test]
375→    fn query_affected_returns_union() {
376→        let mut entries = BTreeMap::new();
377→        entries.insert(
378→            "test_a".to_string(),
379→            TestEntry {
380→                files: BTreeMap::from([("src/a.rs".to_string(), "h1".to_string())]),
381→            },
382→        );
383→        entries.insert(
384→            "test_b".to_string(),
385→            TestEntry {
386→                files: BTreeMap::from([("src/b.rs".to_string(), "h2".to_string())]),
387→            },
388→        );
389→        entries.insert(
390→            "test_c".to_string(),
391→            TestEntry {
392→                files: BTreeMap::from([
393→                    ("src/a.rs".to_string(), "h1".to_string()),
394→                    ("src/b.rs".to_string(), "h2".to_string()),
395→                ]),
396→            },
397→        );
398→
399→        let map = CoverageMap {
400→            data: CoverageMapData {
401→                version: COVERAGE_MAP_VERSION,
402→                recorded_at: "now".to_string(),
403→                entries,
404→            },
405→            reverse: HashMap::new(),
406→        };
407→        let map = CoverageMap {
408→            reverse: build_reverse_index(&map.data.entries),
409→            ..map
410→        };
411→
412→        let result = map.query_affected(&["src/a.rs".to_string()]);
413→        assert!(result.affected_tests.contains(&"test_a".to_string()));
414→        assert!(result.affected_tests.contains(&"test_c".to_string()));
415→        assert!(!result.affected_tests.contains(&"test_b".to_string()));
416→
417→        // Query both files → all three tests
418→        let result = map.query_affected(&["src/a.rs".to_string(), "src/b.rs".to_string()]);
419→        assert_eq!(result.affected_tests.len(), 3);
420→    }
421→
422→    #[test]
423→    fn query_affected_deduplicates() {
424→        let mut entries = BTreeMap::new();
425→        entries.insert(
426→            "test_x".to_string(),
427→            TestEntry {
428→                files: BTreeMap::from([
429→                    ("src/a.rs".to_string(), "h1".to_string()),
430→                    ("src/b.rs".to_string(), "h2".to_string()),
431→                ]),
432→            },
433→        );
434→
435→        let reverse = build_reverse_index(&entries);
436→        let map = CoverageMap {
437→            data: CoverageMapData {
438→                version: COVERAGE_MAP_VERSION,
439→                recorded_at: "now".to_string(),
440→                entries,
441→            },
442→            reverse,
443→        };
444→
445→        // Both files map to test_x — should appear only once
446→        let result = map.query_affected(&["src/a.rs".to_string(), "src/b.rs".to_string()]);
447→        assert_eq!(result.affected_tests, vec!["test_x".to_string()]);
448→    }
