450→    #[test]
451→    fn query_affected_tracks_unmapped_files() {
452→        let map = CoverageMap::empty();
453→        let result = map.query_affected(&["unknown.rs".to_string()]);
454→        assert!(result.affected_tests.is_empty());
455→        assert_eq!(result.unmapped_files, vec!["unknown.rs".to_string()]);
