539→#[cfg(test)]
540→mod proptests {
541→    use super::*;
542→    use proptest::prelude::*;
543→
544→    fn arb_test_entry() -> impl Strategy<Value = TestEntry> {
545→        prop::collection::btree_map(
546→            "[a-z/]{1,20}\\.rs",
547→            "[0-9a-f]{6,12}",
548→            0..=5,
549→        )
550→        .prop_map(|files| TestEntry { files })
551→    }
552→
553→    fn arb_coverage_map_data() -> impl Strategy<Value = CoverageMapData> {
554→        prop::collection::btree_map(
555→            "[a-z_:]{1,30}",
556→            arb_test_entry(),
557→            0..=10,
558→        )
559→        .prop_map(|entries| CoverageMapData {
560→            version: COVERAGE_MAP_VERSION,
561→            recorded_at: "2026-01-01T00:00:00Z".to_string(),
562→            entries,
563→        })
564→    }
565→
566→    proptest! {
567→        /// YAML roundtrip preserves all data.
568→        #[test]
569→        fn yaml_roundtrip(data in arb_coverage_map_data()) {
570→            let yaml = serde_yaml::to_string(&data).unwrap();
571→            let parsed: CoverageMapData = serde_yaml::from_str(&yaml).unwrap();
572→            prop_assert_eq!(data, parsed);
573→        }
574→
575→        /// Reverse index invariant: every (test, file) pair in forward map
576→        /// has file→test in reverse.
577→        #[test]
578→        fn reverse_index_covers_forward(data in arb_coverage_map_data()) {
579→            let reverse = build_reverse_index(&data.entries);
580→            for (test_id, entry) in &data.entries {
581→                for file in entry.files.keys() {
582→                    let tests = reverse.get(file).unwrap();
583→                    prop_assert!(tests.contains(test_id));
584→                }
585→            }
586→        }
587→
588→        /// Query monotonicity: query(A ∪ B) ⊇ query(A).
589→        #[test]
590→        fn query_monotonicity(
591→            data in arb_coverage_map_data(),
592→            extra_files in prop::collection::vec("[a-z/]{1,15}\\.rs", 0..=3),
593→        ) {
594→            let reverse = build_reverse_index(&data.entries);
595→            let map = CoverageMap { data, reverse };
596→
597→            // Collect all known files
598→            let known_files: Vec<String> = map.reverse.keys().cloned().collect();
599→            if known_files.is_empty() {
600→                return Ok(());
601→            }
602→
603→            // Take a subset A
604→            let a: Vec<String> = known_files.iter().take(1).cloned().collect();
605→            // B = A ∪ extra
606→            let mut b = a.clone();
607→            b.extend(extra_files);
608→
609→            let result_a = map.query_affected(&a);
610→            let result_b = map.query_affected(&b);
611→
612→            let set_a: HashSet<_> = result_a.affected_tests.iter().collect();
613→            let set_b: HashSet<_> = result_b.affected_tests.iter().collect();
614→
615→            for t in &set_a {
616→                prop_assert!(set_b.contains(t), "monotonicity violated: {t} in A but not in A∪B");
617→            }
618→        }
619→
620→        /// Reverse index has no duplicates per file.
621→        #[test]
622→        fn reverse_index_no_duplicates(data in arb_coverage_map_data()) {
623→            let reverse = build_reverse_index(&data.entries);
624→            for (_, tests) in &reverse {
625→                let unique: HashSet<_> = tests.iter().collect();
626→                prop_assert_eq!(tests.len(), unique.len());
627→            }
628→        }
629→    }
630→}
