  1→//! Test export: generate test files from behavior maps.
  2→//!
  3→//! Converts a [`BehaviorMap`] into a test file for a specific framework.
  4→//! Supports Jest (TypeScript) and Go table-driven tests.
  5→
  6→use crate::behavior::{Behavior, BehaviorMap};
  7→
  8→/// Generate Jest test source from a behavior map.
  9→///
 10→/// Each behavior becomes an `it` block inside a `describe` block for the function.
 11→/// The generated file includes an import for the function under test.
 12→///
 13→/// # Arguments
 14→/// * `behavior_map` - The behavior map to generate tests from.
 15→/// * `function_name` - The name of the function under test (used in `describe`).
 16→/// * `module_path` - The module path for the import statement (e.g. `"./src/math"`).
 17→pub fn generate_jest_tests(
 18→    behavior_map: &BehaviorMap,
 19→    function_name: &str,
 20→    module_path: &str,
 21→) -> String {
 22→    let mut out = String::new();
 23→
 24→    // Import statement
 25→    out.push_str(&format!(
 26→        "import {{ {function_name} }} from '{module_path}';\n\n"
 27→    ));
 28→
 29→    // Describe block
 30→    out.push_str(&format!("describe('{function_name}', () => {{\n"));
 31→
 32→    if behavior_map.behaviors.is_empty() {
 33→        out.push_str("  // No behaviors observed\n");
 34→    }
 35→
 36→    for behavior in &behavior_map.behaviors {
 37→        let test_name = build_test_name(behavior);
 38→        let body = build_test_body(function_name, behavior);
 39→
 40→        out.push_str(&format!("  it('{test_name}', () => {{\n"));
 41→        out.push_str(&body);
 42→        out.push_str("  });\n\n");
 43→    }
 44→
 45→    out.push_str("});\n");
 46→    out
 47→}
