124→    }
125→    if root.join("package.json").exists() {
126→        runners.push(DetectedRunner {
127→            kind: RunnerKind::Vitest,
128→            root: root.to_path_buf(),
129→        });
130→    }
131→    if root.join("go.mod").exists() {
132→        runners.push(DetectedRunner {
133→            kind: RunnerKind::GoTest,
134→            root: root.to_path_buf(),
135→        });
136→    }
