184→/// Capitalize the first character of a string (for Go exported names).
185→fn capitalize_first(s: &str) -> String {
186→    let mut chars = s.chars();
187→    match chars.next() {
188→        None => String::new(),
189→        Some(c) => c.to_uppercase().collect::<String>() + chars.as_str(),
190→    }
191→}
