234→/// Format a JSON value as a Go literal.
235→///
236→/// Detects `__complex_type` tagged objects and emits constructor calls.
237→fn format_go_value(value: &serde_json::Value) -> String {
238→    if let Some(go) = try_format_complex_go(value) {
239→        return go;
240→    }
241→    match value {
242→        serde_json::Value::String(s) => format!("\"{}\"", s.replace('\\', "\\\\").replace('"', "\\\"")),
243→        serde_json::Value::Null => "nil".to_string(),
244→        serde_json::Value::Bool(b) => b.to_string(),
245→        serde_json::Value::Number(n) => n.to_string(),
246→        other => format!("/* unsupported: {} */nil", other),
247→    }
248→}
